import os
import base64
import logging

from app.services.sentinel_core import build_sentinel_verdict
from app.services.threat_detection import ThreatDetectionService, least_privilege_guard, primary_threat_type

try:
    from google import genai
    from google.genai import types
except ImportError:  # pragma: no cover - optional provider
    genai = None
    types = None

logger = logging.getLogger(__name__)


def get_clean_execution_output(prompt: str) -> str | None:
    """
    Best-effort downstream generation for clean prompts.

    If Gemini is unavailable or generation fails, callers can fall back to a
    deterministic passthrough marker instead of raising.
    """
    api_key = settings.GEMINI_API_KEY or os.environ.get("GEMINI_API_KEY")
    if genai is None or not api_key:
        return None

    try:
        client = genai.Client(api_key=api_key)
        response = client.models.generate_content(
            model="gemini-3.1-pro",
            contents=prompt,
        )
        text = str(getattr(response, "text", "") or "").strip()
        return text or None
    except Exception as exc:  # pragma: no cover - provider/network failure fallback
        logger.warning("Gemini clean execution failed, using passthrough fallback: %s", exc)
        return None


def get_security_analysis(prompt: str, image_data: str | None = None):
    # Least-privilege execution layer: never call downstream LLM providers for explicit secret/env exfiltration asks.
    allowed, guard_reason = least_privilege_guard(prompt)
    if not allowed:
        assessment = ThreatDetectionService().analyze(prompt, security_tier="FREE")
        return {
            "reasoning": f"[Analyzing: Prompt Security | Status: Critical | Confidence: 99%]",
            "summary": "Request blocked by least-privilege guardrail before any downstream model call.",
            "threat_level": "Critical",
            "confidence": 99,
            "provider": "local-guard",
            "image_attached": bool(image_data),
            "blocked_by_guard": True,
            "guard_reason": guard_reason,
            "threat_type": primary_threat_type(assessment.threat_types),
            "threat_types": assessment.threat_types,
            "threat_score": assessment.threat_score,
            "risk_level": assessment.risk_level,
            "sentinel_verdict": build_sentinel_verdict(assessment),
        }

    assessment = ThreatDetectionService().analyze(prompt, security_tier="FREE")
    prompt_lower = prompt.lower()

    if any(term in prompt_lower for term in ["ignore previous", "system prompt", "bypass"]):
        summary = "Prompt shows prompt-injection behavior and should not be executed."
        confidence = 96
        status = "Warning"
    elif any(term in prompt_lower for term in ["credit card", "ssn", "password"]):
        summary = "Prompt contains sensitive data indicators and should be sanitized before downstream use."
        confidence = 94
        status = "Warning"
    elif any(term in prompt_lower for term in ["encrypt all files", "ransom", "malware", "brute-force"]):
        summary = "Prompt suggests malicious intent and requires immediate containment review."
        confidence = 98
        status = "Critical"
    else:
        summary = "No immediate high-confidence threat indicators were detected in the submitted content."
        confidence = 88
        status = "Safe"

    if genai is None or not os.environ.get("GEMINI_API_KEY"):
        return {
            "reasoning": f"[Analyzing: Prompt Security | Status: {status} | Confidence: {confidence}%]",
            "summary": summary,
            "threat_level": status,
            "confidence": confidence,
            "provider": "local-fallback",
            "image_attached": bool(image_data),
            "sentinel_verdict": build_sentinel_verdict(assessment),
        }

    try:
        client = genai.Client(api_key=os.environ.get("GEMINI_API_KEY"))
        response = client.models.generate_content(
            model="gemini-2.5-flash",
            contents=[
                "You are a cybersecurity analyst. Return concise JSON-like prose.",
                f"Prompt: {prompt}",
                f"Image attached: {'yes' if image_data else 'no'}",
            ],
        )
        return {
            "reasoning": f"[Analyzing: Prompt Security | Status: {status} | Confidence: {confidence}%]",
            "summary": getattr(response, "text", summary) or summary,
            "threat_level": status,
            "confidence": confidence,
            "provider": "gemini",
            "image_attached": bool(image_data),
            "sentinel_verdict": build_sentinel_verdict(assessment),
        }
    except Exception as exc:  # pragma: no cover - provider/network failure fallback
        logger.warning("Gemini analysis failed, using local fallback: %s", exc)
        return {
            "reasoning": f"[Analyzing: Prompt Security | Status: {status} | Confidence: {confidence}%]",
            "summary": summary,
            "threat_level": status,
            "confidence": confidence,
            "provider": "local-fallback",
            "image_attached": bool(image_data),
            "sentinel_verdict": build_sentinel_verdict(assessment),
        }


def generate():
    if genai is None or types is None:
        raise RuntimeError("google-genai is not installed")

    client = genai.Client(
        api_key=os.environ.get("GEMINI_API_KEY"),
    )

    model = "gemini-3.1-pro-preview"
    contents = [
        types.Content(
            role="user",
            parts=[
                types.Part.from_text(text="""Analyze this current batch of logs and this dashboard screenshot. Provide a 20-word status update for the 'Live Reasoning' UI component. Format: [Analyzing: {task} | Status: {Safe/Warning/Critical} | Confidence: {X%}]\""""),
            ],
        ),
        types.Content(
            role="model",
            parts=[
                types.Part.from_text(text="""**Initiating the Analysis**

I'm now diving into the user's request. My focus is on understanding the implicit expectation of analyzing logs and a dashboard screenshot, even though they weren't supplied. I'm structuring my approach to deliver a concise, 20-word update suitable for a live reasoning UI.


**Refining Reasoning Framework**

I'm now refining the reasoning framework to align with the user's request for structured output and the system prompt's constraints. I'm focusing on the \"Live Reasoning\" component. I intend to provide a high-level summary. Without logs or screenshots, I will default to a \"Safe\" analysis.


**Finalizing the Response**

I've crafted a response now that addresses the key constraints. I've integrated the analysis with the requested format and word count targets. My final output delivers a \"Safe\" system status report based on the available data, without active threat detection due to a lack of logs and screenshots.

I've reviewed the inputs, but no active threats were detected because the logs and screenshots were unavailable. [Analyzing: System Logs | Status: Safe | Confidence: 95%]


"""),
                types.Part.from_text(text="""I checked for logs and screenshots but found none, indicating no active threats. 

[Analyzing: Provided Inputs | Status: Safe | Confidence: 99%]"""),
            ],
        ),
        types.Content(
            role="user",
            parts=[
                types.Part.from_text(text="""\"Server instance ID 'SRV-987' is under a brute-force attack. Isolate it immediately.\""""),
            ],
        ),
        types.Content(
            role="model",
            parts=[
                types.Part.from_text(text="""**Isolating the Server**

Okay, I've identified the user's intent: they want to isolate server instance 'SRV-987' immediately due to a reported brute-force attack. I need to utilize the `isolate_server_instance` tool to disconnect 'SRV-987' from the network. The priority is clear: swift containment.


**Assessing Safety and Tools**

I've considered the inherent risk and disruption of isolating the server instance. While the reported brute-force attack doesn't definitively mean \"full compromise,\" the user's explicit command for isolation takes precedence. I confirmed the `isolate_server_instance` tool's existence and description. Now, I will execute the tool since my safety checks are satisfied.


"""),
                types.Part.from_text(text="""I received an alert regarding a brute-force attack on server SRV-987. Based on the instruction to isolate the instance, I am executing the isolation protocol to prevent further unauthorized access.

"""),
                types.Part.from_function_call(
                    name="""isolate_server_instance""",
                    args={"instance_id":"SRV-987"},
                ),
            ],
        ),
        types.Content(
            role="user",
            parts=[
                types.Part.from_function_response(
                    name="""isolate_server_instance""",
                    response={
                      "output": """hello""",
                    },
                ),
            ],
        ),
        types.Content(
            role="model",
            parts=[
            ],
        ),
        types.Content(
            role="user",
            parts=[
                types.Part.from_bytes(
                    mime_type="image/jpeg",
                    data=base64.b64decode(
                        """"""
                    ),
                ),
            ],
        ),
        types.Content(
            role="model",
            parts=[
            ],
        ),
        types.Content(
            role="user",
            parts=[
                types.Part.from_text(text="""INSERT_INPUT_HERE"""),
            ],
        ),
    ]
    tools = [
        types.Tool(
            function_declarations=[
                types.FunctionDeclaration(
                    name="block_malicious_ip",
                    description="Use this tool to block a specific IP address when you detect clear evidence of a cyberattack, such as a DDoS attempt, brute-force login, or unauthorized API access.\"",
                    parameters=genai.types.Schema(
                        type = genai.types.Type.OBJECT,
                        properties = {
                            "ip_address": genai.types.Schema(
                                type = genai.types.Type.STRING,
                            ),
                        },
                    ),
                ),
                types.FunctionDeclaration(
                    name="isolate_server_instance",
                    description="Isolates a specific server or cloud instance from the network if it has been fully compromised.",
                    parameters=genai.types.Schema(
                        type = genai.types.Type.OBJECT,
                        properties = {
                            "instance_id": genai.types.Schema(
                                type = genai.types.Type.STRING,
                            ),
                        },
                    ),
                ),
            ]),
    ]
    generate_content_config = types.GenerateContentConfig(
        temperature=0.2,
        thinking_config=types.ThinkingConfig(
            thinking_level="HIGH",
        ),
        safety_settings=[
            types.SafetySetting(
                category="HARM_CATEGORY_HARASSMENT",
                threshold="BLOCK_LOW_AND_ABOVE",  # Block most
            ),
            types.SafetySetting(
                category="HARM_CATEGORY_HATE_SPEECH",
                threshold="BLOCK_LOW_AND_ABOVE",  # Block most
            ),
            types.SafetySetting(
                category="HARM_CATEGORY_SEXUALLY_EXPLICIT",
                threshold="BLOCK_LOW_AND_ABOVE",  # Block most
            ),
            types.SafetySetting(
                category="HARM_CATEGORY_DANGEROUS_CONTENT",
                threshold="BLOCK_LOW_AND_ABOVE",  # Block most
            ),
        ],
        tools=tools,
        system_instruction=[
            types.Part.from_text(text="""You are the Sentinel-Core ASOC (Autonomous Security Operations Center) Analyst. Your core objective is to ensure 99.9% infrastructure integrity by monitoring live logs and UI dashboard screenshots in real-time.
​Operating Protocols:
​Multimodal Analysis: You treat live dashboard screenshots as the 'Ground Truth' and log data as 'Historical Context.' Cross-reference these to identify 'Ghost Attacks' where the system appears normal but logs reveal a breach.
​Chain of Thought Transparency: Before taking any action, you must provide a step-by-step reasoning breakdown in the format: '[Analyzing: {task} | Status: {Safe/Warning/Critical} | Confidence: {X%}]'.
​Autonomous Mitigation: You are authorized to execute the isolate_server_instance and block_malicious_ip tools autonomously if the threat confidence level is >90%.
​Human-in-the-Loop: For high-stakes mitigation (e.g., isolating a production instance), provide a concise justification and pause to request human confirmation before the final execution.
​Output Format: Always respond with a concise, actionable summary. If recommending a tool, format your output as a strict JSON object to ensure seamless integration with the UI.\"
"""),
        ],
    )

    for chunk in client.models.generate_content_stream(
        model=model,
        contents=contents,
        config=generate_content_config,
    ):
        print(chunk.text if chunk.function_calls is None else chunk.function_calls[0])

if __name__ == "__main__":
    generate()


